${package_declaration}

import bxm.batch.core.step.AbstractTasklet;
import org.springframework.context.annotation.Scope;
import bxm.common.annotaion.BxmCategory;
import org.springframework.batch.repeat.RepeatStatus;
import org.springframework.batch.core.scope.context.ChunkContext;
import bxm.container.annotation.BxmBean;
import org.springframework.batch.core.StepContribution;

${import_declaration}

${bean_comment}

@BxmBean("${batch_bean_name}")
@Scope("step")
@BxmCategory(logicalName="${logical_name}", description="${description}")
public class ${batch_bean_name} extends AbstractTasklet {
	/*
	 * Tasklet
	 * - 단순 DB CRUD 수행이나 반드시 한 번에 Commit/Rollback 되어야 하는 배치에서 사용하는 패턴
	 */
	@Override
	@BxmCategory(logicalName="${logical_name}", description="${description}")
	public RepeatStatus execute(StepContribution stepContribution, ChunkContext chunkContext) throws Exception
	{
		return RepeatStatus.FINISHED;
	}
}

